svg.script:
(function () {
  var PHASES = [
    'Nitrogen (N₂) and oxygen (O₂) float in the storm cloud…',
    '⚡ Lightning! 30,000°C — hotter than the Sun!',
    'The blast tears BOTH molecules into single atoms!',
    'A nitrogen grabs an oxygen → NO (nitric oxide)',
    'NO grabs one more oxygen → NO₂',
    'Spare oxygen rejoins as O₂ — or O₃, the ozone smell!',
    'Rain dissolves NO₂ into nitrate (NO₃⁻)…',
    '…the plant food that soaks into the soil!'
  ];

  function setPhase(txt) {
    var el = document.getElementById('nltg-phase');
    if (el) el.textContent = txt;
  }
  function setMol(txt) {
    var l = document.getElementById('nltg-mol-left');
    var r = document.getElementById('nltg-mol-right');
    if (l) l.textContent = txt;
    if (r) r.textContent = txt;
  }

  function animate() {
    /* Reset every element to its initial state */
    gsap.set('#nltg-n-left',  { x: 0, y: 0 });
    gsap.set('#nltg-n-right', { x: 0, y: 0 });
    gsap.set(['#nltg-bond1', '#nltg-bond2', '#nltg-bond3'], { opacity: 1 });
    gsap.set(['#nltg-o2bond-l', '#nltg-o2bond-r', '#nltg-o2bond-x'], { opacity: 1 });
    gsap.set('#nltg-o-l1', { x: 0, y: 0 });
    gsap.set('#nltg-o-l2', { x: 0, y: 0 });
    gsap.set('#nltg-o-r1', { x: 0, y: 0 });
    gsap.set('#nltg-o-r2', { x: 0, y: 0 });
    gsap.set('#nltg-o-x1', { x: 0, y: 0 });
    gsap.set('#nltg-o-x2', { x: 0, y: 0 });
    gsap.set('#nltg-o2-text', { opacity: 0 });
    gsap.set(['#nltg-nobond-l1', '#nltg-nobond-l2',
              '#nltg-nobond-r1', '#nltg-nobond-r2'], { opacity: 0, y: 0 });
    gsap.set(['#nltg-mol-left', '#nltg-mol-right'], { opacity: 0, y: 0 });
    gsap.set('#nltg-ozone', { opacity: 0 });
    gsap.set('#nltg-lightning',      { opacity: 0 });
    gsap.set('#nltg-lightning-glow', { opacity: 0 });
    gsap.set('#nltg-flash',          { opacity: 0 });
    gsap.set('.nltg-rain',           { opacity: 0, y: 0 });
    gsap.set('#nltg-ground-glow',    { opacity: 0 });
    gsap.set('#nltg-plant',  { opacity: 0, scaleY: 0 });
    gsap.set('#nltg-label',  { opacity: 0 });
    gsap.set('#nltg-replay', { opacity: 0 });
    gsap.set('#nltg-phase',  { opacity: 0 });
    setMol('NO');

    var tl = gsap.timeline();

    tl
      /* Phase 0 — N₂ and O₂ drift in the cloud */
      .call(function () { setPhase(PHASES[0]); })
      .to('#nltg-phase', { opacity: 1, duration: 0.6 })

      /* Phase 1 — lightning strikes */
      .call(function () { setPhase(PHASES[1]); }, null, '+=0.9')
      .to('#nltg-lightning-glow', { opacity: 0.65, duration: 0.08 })
      .to('#nltg-lightning',      { opacity: 1,    duration: 0.08 }, '<')
      .to('#nltg-flash',          { opacity: 0.85, duration: 0.08 }, '<')
      .to('#nltg-lightning-glow', { opacity: 0, duration: 0.55 })
      .to('#nltg-lightning',      { opacity: 0, duration: 0.50 }, '<+=0.1')
      .to('#nltg-flash',          { opacity: 0, duration: 0.45 }, '<')

      /* Phase 2 — BOTH molecules dissociate into single atoms */
      .call(function () { setPhase(PHASES[2]); })
      /* N₂ triple bond breaks; nitrogens drift to their reaction spots */
      .to('#nltg-n-left',  { x: -25, y: 38, duration: 0.6, ease: 'power2.out' })
      .to('#nltg-n-right', { x:  25, y: 38, duration: 0.6, ease: 'power2.out' }, '<')
      .to(['#nltg-bond1', '#nltg-bond2', '#nltg-bond3'],
          { opacity: 0, duration: 0.3 }, '<')
      /* O₂ bonds snap; the spare oxygen pair drifts apart */
      .to(['#nltg-o2bond-l', '#nltg-o2bond-r', '#nltg-o2bond-x'],
          { opacity: 0, duration: 0.3 }, '<')
      .to('#nltg-o-x1', { x: -18, duration: 0.6, ease: 'power2.out' }, '<')
      .to('#nltg-o-x2', { x:  18, duration: 0.6, ease: 'power2.out' }, '<')

      /* Phase 3 — N + O → NO */
      .call(function () { setPhase(PHASES[3]); }, null, '+=0.3')
      .to('#nltg-o-l1', { x: 55, y: 58, duration: 0.7, ease: 'power2.out' })
      .to('#nltg-o-r1', { x: -55, y: 58, duration: 0.7, ease: 'power2.out' }, '<')
      .to(['#nltg-nobond-l1', '#nltg-nobond-r1'],
          { opacity: 1, duration: 0.35 }, '<+=0.45')
      .call(function () { setMol('NO'); })
      .to(['#nltg-mol-left', '#nltg-mol-right'], { opacity: 1, duration: 0.35 })

      /* Phase 4 — NO + O → NO₂ */
      .call(function () { setPhase(PHASES[4]); }, null, '+=0.4')
      .to('#nltg-o-l2', { x: 58, y: 22, duration: 0.7, ease: 'power2.out' })
      .to('#nltg-o-r2', { x: -58, y: 22, duration: 0.7, ease: 'power2.out' }, '<')
      .to(['#nltg-nobond-l2', '#nltg-nobond-r2'],
          { opacity: 1, duration: 0.35 }, '<+=0.45')
      .call(function () { setMol('NO₂'); })

      /* Phase 5 — spare oxygen rejoins as O₂ / ozone (O₃) */
      .call(function () { setPhase(PHASES[5]); }, null, '+=0.4')
      .to('#nltg-o-x1', { x: 0, duration: 0.55, ease: 'power2.inOut' })
      .to('#nltg-o-x2', { x: 0, duration: 0.55, ease: 'power2.inOut' }, '<')
      .to('#nltg-o2bond-x', { opacity: 1, duration: 0.3 }, '<+=0.35')
      .to('#nltg-o2-text',  { opacity: 1, duration: 0.3 }, '<')
      .to('#nltg-ozone',    { opacity: 1, duration: 0.5 }, '+=0.1')

      /* Phase 6 — rain dissolves NO₂ into nitrate (NO₃⁻) */
      .call(function () { setPhase(PHASES[6]); }, null, '+=0.4')
      .to('.nltg-rain',
        { opacity: 0.8, y: 70, duration: 1.3, stagger: 0.07, ease: 'power1.in' })
      .call(function () { setMol('NO₃⁻'); }, null, '<+=0.5')
      .to([
          '#nltg-n-left',  '#nltg-o-l1', '#nltg-o-l2',
          '#nltg-nobond-l1', '#nltg-nobond-l2', '#nltg-mol-left',
          '#nltg-n-right', '#nltg-o-r1', '#nltg-o-r2',
          '#nltg-nobond-r1', '#nltg-nobond-r2', '#nltg-mol-right'
        ],
        { y: '+=90', duration: 1.4, ease: 'power1.in' }, '<')

      /* Phase 7 — nitrate soaks in, plant grows */
      .call(function () { setPhase(PHASES[7]); })
      .to('#nltg-ground-glow', { opacity: 0.7, duration: 0.3 })
      .to('#nltg-ground-glow', { opacity: 0,   duration: 1.0 })
      .to('#nltg-plant',
        { opacity: 1, scaleY: 1, duration: 0.85, ease: 'elastic.out(1, 0.5)' }, '<')

      /* End — formula label and replay button */
      .to('#nltg-label',  { opacity: 1, duration: 0.5 }, '+=0.2')
      .to('#nltg-replay', { opacity: 1, duration: 0.4 }, '+=0.2');
  }

  window.nltgReplay = function () {
    if (window.gsap) animate();
  };

  function setup() {
    var svgEl = document.getElementById('nltg-svg');
    if (!svgEl) return;
    var played = false;
    var io = new IntersectionObserver(function (entries) {
      if (entries[0].isIntersecting && !played) {
        played = true;
        io.disconnect();
        animate();
      }
    }, { threshold: 0.3 });
    io.observe(svgEl);
  }

  if (window.gsap) {
    setup();
  } else {
    var s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/gsap.min.js';
    s.onload = setup;
    document.head.appendChild(s);
  }
}());
